# LBYL â€” double lookup, possible TOCTOU race
if "user_id" in request.data:
    user_id = request.data["user_id"]
    if user_id in user_cache:
        user = user_cache[user_id]
    else:
        user = None

try:
    user_id = int(request.data["user_id"])
    user = User.objects.get(id=user_id)
    send_welcome_email(user)  # Bug here silently swallowed!
except (ValueError, KeyError, User.DoesNotExist):
    return Response({"error": "invalid"}, status=400)

try:
    user_id = int(request.data["user_id"])
except (ValueError, KeyError):
    return Response({"error": "user_id must be an integer"}, status=400)

try:
    user = User.objects.get(id=user_id)
except User.DoesNotExist:
    return Response({"error": "user not found"}, status=404)

send_welcome_email(user)  # Allowed to raise freely â€” bug visibility preserved

class OrderError(Exception):
    """Base for all order domain errors."""

class OrderNotFound(OrderError):
    def __init__(self, order_id: int) -> None:
        self.order_id = order_id
        super().__init__(f"Order {order_id} not found")

class InsufficientStock(OrderError):
    def __init__(self, product_id: int, requested: int, available: int) -> None:
        self.product_id = product_id
        self.requested = requested
        self.available = available
        super().__init__(
            f"Product {product_id}: requested {requested}, available {available}"
        )

# Caller can catch broadly or specifically
try:
    process_order(order_id)
except InsufficientStock as e:
    notify_reorder(e.product_id)
except OrderError as e:
    logger.warning("Order error: %s", e)
